import logging
import math
import os
import random
import time
from enum import Enum
from typing import List

import numpy as np
from geosat.cloud import PointCloud, pyvoxels

# 2 types of KDTrees are used because they do not perform equally for their use-case:
from pykdtree.kdtree import KDTree
from scipy.spatial import cKDTree
from tensorflow import keras

from psanp.classifiers.tensorflow.susann_v2_classifier.settings import Settings

NO_DATA = 0.0


class LazLoaderMode(Enum):
    TRAIN = 1
    VALIDATION = 2
    INFERENCE = 3


class LazLoader(keras.utils.Sequence):
    def __init__(
        self,
        pointcloud: PointCloud,
        settings: Settings,
        mode=LazLoaderMode.INFERENCE,
        sampling_method="default",
    ):
        # Storing settings
        self.settings = settings
        self.mode = mode
        self.sampling_method = sampling_method

        # Initialization
        self.current_epoch = -1
        self._batch_indexes = np.arange(0)

        # Loading pointcloud
        logging.debug("Processing pointcloud")
        self._load_pointcloud(pointcloud)
        self.on_epoch_end()
        self.reset_output()

    def _load_pointcloud(self, pointcloud):
        self.pointcloud = pointcloud
        logging.debug(f" - Dataset contains {len(self.pointcloud)} points")

        # Gathering volumes centers
        start_time = time.time()
        self.subsampled_pointcloud = pyvoxels.voxelize_cloud(
            self.pointcloud, self.settings.data.resolution
        )
        self.points = (
            np.array(list(self.subsampled_pointcloud), dtype=np.float32).reshape(
                (-1, 3)
            )
            * self.settings.data.resolution
        )
        self.points_indices = np.array(
            [v[0] for v in self.subsampled_pointcloud.values()], dtype=np.int32
        )
        self.labels = np.array(self.pointcloud.classification[self.points_indices])
        logging.debug(
            f" - Subsampled dataset contains {len(self.points)} points at resolution "
            f"{self.settings.data.resolution}m ({time.time() - start_time:0.2f}s)"
        )

        # Building tree
        start_time = time.time()
        self.tree = cKDTree(self.points)
        logging.debug(f" - Built tree ({(time.time() - start_time):02f}s)")

    def on_epoch_end(self):
        # If balancing is required
        if self.sampling_method == "balanced":
            max_occurrence_per_class = self.settings.data.sampling_class_occurences
            # Iterate through each class, and elect N candidate volumes
            single_class_volumes = []
            for cls in range(self.settings.data.n_classes):
                if cls in self.settings.data.ignore_classes:
                    continue

                # Retrieve candidate voxel of class CLS
                relevant_points = np.random.permutation(
                    np.argwhere(self.labels == cls).ravel()
                )

                if len(relevant_points) > max_occurrence_per_class:
                    relevant_points = relevant_points[:max_occurrence_per_class]
                else:
                    n_repeats = (
                        math.floor(max_occurrence_per_class / len(relevant_points)) + 1
                    )
                    relevant_points = np.random.permutation(
                        np.repeat(relevant_points, n_repeats, axis=0)
                    )[:max_occurrence_per_class]

                # Add as many candidate as possible to the list
                single_class_volumes.extend(relevant_points)

            # Randomize each elected samples
            single_class_volumes = np.array(single_class_volumes)
            self._batch_indexes = single_class_volumes[
                np.random.permutation(np.arange(len(single_class_volumes)))
            ]
        else:
            # Tries to estimate how many batches should be processed to cover all the data
            if len(self.points) < self.settings.network.max_num_points:
                self._batch_indexes = np.arange(0)
            else:
                batch_indexes = self._query_batch_indexes()

                # Fill batch_indexes to be a multiple of batch_size
                left = len(batch_indexes) % self.settings.network.batch_size
                if left > 0:
                    batch_indexes.extend(
                        [
                            batch_indexes[-1]
                            for _ in range(self.settings.network.batch_size - left)
                        ]
                    )
                self._batch_indexes = batch_indexes

    def _query_batch_indexes(self) -> List[int]:
        to_process = np.ones(len(self.points), np.bool_)
        index = 0
        batch_indexes: List[int] = []
        while True:
            try:
                index = (
                    next(i for i, to_proc in enumerate(to_process[index:]) if to_proc)
                    + index
                )
            except StopIteration:
                break
            batch_indexes.append(index)
            _, nn = self.tree.query(
                self.points[index].reshape(1, -1),
                k=self.settings.network.max_num_points,
            )
            to_process[nn[0]] = False
        return batch_indexes

    def get_training_steps(self):
        return len(self) * self.settings.network.epochs

    def get_input_dimensions_and_offsets(self):
        offsets = [0]
        for level in range(self.settings.network.levels):
            offsets.append(
                int(offsets[-1] + self.settings.network.max_num_points / (4**level))
            )
        return offsets[-1], offsets

    def __len__(self):
        return int(
            np.floor(len(self._batch_indexes) / self.settings.network.batch_size)
        )

    def __getitem__(self, batch_index):
        batch_size = self.settings.network.batch_size
        max_num_pts = self.settings.network.max_num_points
        k_neighbors = self.settings.network.k_neighbors

        # Extract voxel idx for the current batch
        self._batch_idx = self._batch_indexes[
            batch_index * batch_size : (batch_index + 1) * batch_size
        ]

        # Create input/outputs
        num_input_elements, input_offsets = self.get_input_dimensions_and_offsets()
        inputs = np.full((batch_size, num_input_elements, 3 + k_neighbors + 2), NO_DATA)
        output = np.full((batch_size, max_num_pts, 4), NO_DATA)  # label, mask, idx

        # Iterates through batch indices
        for b_i, sample_id in enumerate(self._batch_idx):
            _, points_idx = self.tree.query(
                self.points[sample_id].reshape(1, -1), k=max_num_pts
            )
            points_idx = np.random.permutation(points_idx[0])

            relative_points = self.points[points_idx] - self.points[sample_id].reshape(
                1, -1
            )

            if self.mode == LazLoaderMode.TRAIN:
                if "rotation" in self.settings.data.augmentation:
                    relative_points = self.rotate2d(
                        relative_points, random.random() * 2 * np.pi
                    )
                if "scale" in self.settings.data.augmentation:
                    relative_points = relative_points * random.uniform(0.95, 1.10)
                if "noise" in self.settings.data.augmentation:
                    relative_points = (
                        relative_points
                        + ((np.random.random((len(relative_points), 3)) - 0.5) * 2)
                        * 0.02
                    )
                if (
                    "flip_x" in self.settings.data.augmentation
                    and random.random() > 0.5
                ):
                    relative_points[:, 0] = -relative_points[:, 0]
                if (
                    "flip_y" in self.settings.data.augmentation
                    and random.random() > 0.5
                ):
                    relative_points[:, 1] = -relative_points[:, 1]

            num_pts = len(points_idx)
            if self.mode != LazLoaderMode.INFERENCE:
                output[b_i, :num_pts, 0] = self.labels[points_idx]
            output[b_i, :num_pts, 1] = 1
            output[b_i, :num_pts, 2] = points_idx
            output[b_i, :num_pts, 3] = np.sqrt(np.sum(relative_points**2, axis=-1))

            tree = KDTree(relative_points)
            for level_start_idx in input_offsets[:-1]:
                _, n_idx = tree.query(
                    relative_points,
                    k=k_neighbors,
                    # Distances are not used: there is no need to sqrt them:
                    sqr_dists=True,
                )
                num_subsampled = np.ceil(
                    np.maximum(len(relative_points) / 4, k_neighbors)
                ).astype(int)
                sub_points = np.random.choice(
                    np.arange(len(relative_points)), num_subsampled
                )

                tree = KDTree(relative_points[sub_points])
                _, us_idx = tree.query(
                    relative_points,
                    k=1,
                    # Distances are not used: there is no need to sqrt them:
                    sqr_dists=True,
                )
                inputs[
                    b_i,
                    level_start_idx : level_start_idx + len(relative_points),
                    :3,
                ] = relative_points
                inputs[
                    b_i,
                    level_start_idx : level_start_idx + len(n_idx),
                    3 : 3 + k_neighbors,
                ] = n_idx
                inputs[
                    b_i,
                    level_start_idx : level_start_idx + num_subsampled,
                    3 + k_neighbors,
                ] = sub_points
                inputs[
                    b_i,
                    level_start_idx : level_start_idx + len(us_idx),
                    3 + k_neighbors + 1,
                ] = us_idx.ravel()
                relative_points = relative_points[sub_points]

        return inputs, output

    def rotate2d(self, pts, alpha):
        pts_rot = np.copy(pts)
        pts_rot[:, 0] = np.cos(alpha) * pts[:, 0] - np.sin(alpha) * pts[:, 1]
        pts_rot[:, 1] = np.sin(alpha) * pts[:, 0] + np.cos(alpha) * pts[:, 1]
        return pts_rot

    def reset_output(self):
        self.predicted_labels = np.zeros(len(self.points), np.uint8)
        self.predicted_dists = np.full(len(self.points), np.inf)
        self.predicted_scores = np.zeros(len(self.points))
        self.processed_batch = 0

    def reset_statistics(self):
        self._num_occurences = np.zeros(self.settings.data.n_classes)
        self._num_retrieved = np.zeros(self.settings.data.n_classes)
        self._confusion_matrix = np.zeros(
            (self.settings.data.n_classes, self.settings.data.n_classes), dtype=np.int_
        )

    def track_statistics(self):
        for cls in range(self.settings.data.n_classes):
            self._num_occurences[cls] += np.sum((self.labels == cls))
            for m_cls in range(self.settings.data.n_classes):
                self._confusion_matrix[cls, m_cls] += np.sum(
                    self.predicted_labels[(self.labels == cls)] == m_cls
                )
                if m_cls == cls:
                    self._num_retrieved[cls] += np.sum(
                        self.predicted_labels[(self.labels == cls)] == cls
                    )

    def get_statistics(self):
        return self._num_retrieved, self._num_occurences, self._confusion_matrix

    def project_batch(self, predictions_hot, points_masks, points_idx, points_dists):
        if (
            len(predictions_hot.shape) >= 3
        ):  # for unit test support, check if prediction are "one_hot" encoded
            predictions = np.argmax(predictions_hot, axis=-1)
            scores = np.amax(predictions_hot, axis=-1)
        else:
            predictions = predictions_hot
            scores = np.ones(len(predictions))

        for sample in range(len(predictions)):
            prediction = np.squeeze(predictions[sample])
            score = np.squeeze(scores[sample])
            points_ids = np.squeeze(points_idx[sample]).astype(np.int_)
            points_dist = np.squeeze(points_dists[sample])
            points_mask = np.squeeze(points_masks[sample]) == 1
            points_mask[points_mask] = (
                self.predicted_dists[points_ids[points_mask]] > points_dist[points_mask]
            )
            self.predicted_labels[points_ids[points_mask]] = prediction[points_mask]
            self.predicted_dists[points_ids[points_mask]] = points_dist[points_mask]
            self.predicted_scores[points_ids[points_mask]] = score[points_mask]

            self.processed_batch += 1

    def project_to_pointcloud(self, save_scores=False, save_distances=False):
        start_time = time.time()

        # Clip extreme distance values
        self.predicted_dists[self.predicted_dists >= np.inf] = 0

        voxels_indices = np.array(
            [
                v_index
                for v_index, pt_indices in enumerate(
                    self.subsampled_pointcloud.values()
                )
                for _ in range(len(pt_indices))
            ],
            dtype=np.int32,
        )
        point_indices = np.array(
            [
                pt_index
                for pt_indices in self.subsampled_pointcloud.values()
                for pt_index in pt_indices
            ],
            dtype=np.int32,
        )
        self.pointcloud.classification[point_indices] = self.predicted_labels[
            voxels_indices
        ]

        if save_scores:
            self.pointcloud.fields["score"] = np.zeros(len(self.pointcloud), np.float32)
            self.pointcloud.score[point_indices] = self.predicted_scores[voxels_indices]
        if save_distances:
            self.pointcloud.fields["distance"] = np.zeros(
                len(self.pointcloud), np.float32
            )
            self.pointcloud.distance[point_indices] = self.predicted_dists[
                voxels_indices
            ]

        # FOR CLOUDCOMPARE VISUALISATION ONLY
        if "synthetic" in self.pointcloud.fields:
            self.pointcloud.synthetic[:] = 0
        logging.debug(
            f" - Projected to pointcloud in {(time.time() - start_time):0.2f}s"
        )

    def save_pointcloud(self, filename):
        self.pointcloud.save(filename)

    def save_prediction_and_gt(self, pred_filename, gt_filename):
        pc = PointCloud(
            self.points,
            fields={"classification": self.predicted_labels.astype(np.uint8)},
        )
        pc.fields["score"] = self.predicted_scores
        dists_tmp = self.predicted_dists
        dists_tmp[dists_tmp >= np.inf] = 0
        pc.fields["distance"] = self.predicted_dists
        pc.save(os.path.join(self.settings.outputs.path, pred_filename))

        pc = PointCloud(
            self.points, fields={"classification": self.labels.astype(np.uint8)}
        )
        pc.save(os.path.join(self.settings.outputs.path, gt_filename))
